#include <stdio.h>

int main() {
    int T, n, a;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        if (scanf("%d", &n) != 1) return 0;
        a = 0;
        while (a < n) {
            printf("%d\n", a);
            a++;
        }
    }
    return 0;
}

